import { NgClass } from '@angular/common';
import { Component, HostListener, Input, computed, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { Router, RouterLink, RouterLinkActive } from '@angular/router';
import { Artwork } from '../../interfaces/artwork.interface';
import { SiteLanguage } from '../../interfaces/language.interface';
import { SiteSocialLinks } from '../../interfaces/site-config.interface';
import { ArtworkService } from '../../services/artwork.service';
import { LanguageSwitcherComponent } from '../language-switcher/language-switcher.component';
import { SocialLinksComponent } from '../social-links/social-links.component';

@Component({
  selector: 'app-header',
  standalone: true,
  imports: [
    NgClass,
    FormsModule,
    RouterLink,
    RouterLinkActive,
    SocialLinksComponent,
    LanguageSwitcherComponent
  ],
  templateUrl: './header.component.html',
  styleUrl: './header.component.sass'
})
export class HeaderComponent {
  constructor(
    private readonly artworkService: ArtworkService,
    private readonly router: Router
  ) {
    this.artworkService.getArtworks().subscribe((artworks) => {
      this.artworks.set(artworks);
    });
  }

  @Input({ required: true }) artistName = '';
  @Input({ required: true }) socialLinks!: SiteSocialLinks;
  @Input({ required: true }) currentLanguage!: SiteLanguage;
  @Input({ required: true }) italianPath!: string;
  @Input({ required: true }) englishPath!: string;

  protected readonly menuOpen = signal(false);
  protected readonly scrolled = signal(false);
  protected readonly searchOpen = signal(false);
  protected readonly searchQuery = signal('');
  private readonly artworks = signal<Artwork[]>([]);

  protected readonly searchResults = computed(() => {
    const query = this.normalizeSearchValue(this.searchQuery());

    if (query.length < 2) {
      return [];
    }

    return this.artworks()
      .filter((artwork) => this.matchesArtworkSearch(artwork, query))
      .slice(0, 8);
  });

  protected readonly hasSearchQuery = computed(() => this.searchQuery().trim().length >= 2);

  @HostListener('window:scroll')
  onWindowScroll(): void {
    this.scrolled.set(window.scrollY > 24);
  }

  @HostListener('document:keydown.escape')
  onEscape(): void {
    this.closeSearch();
  }

  protected toggleMenu(): void {
    this.searchOpen.set(false);
    this.menuOpen.set(!this.menuOpen());
  }

  protected closeMenu(): void {
    this.menuOpen.set(false);
  }

  protected toggleSearch(): void {
    this.menuOpen.set(false);
    this.searchOpen.set(!this.searchOpen());
  }

  protected closeSearch(): void {
    this.searchOpen.set(false);
    this.searchQuery.set('');
  }

  protected updateSearchQuery(value: string): void {
    this.searchQuery.set(value);
  }

  protected navigateToArtwork(artwork: Artwork): void {
    const commands = this.currentLanguage === 'it'
      ? ['/it/opere', artwork.slug]
      : ['/en/artworks', artwork.slug];

    this.closeSearch();
    this.router.navigate(commands);
  }

  protected openArchive(): void {
    const commands = this.currentLanguage === 'it'
      ? ['/it/opere']
      : ['/en/artworks'];

    this.closeSearch();
    this.router.navigate(commands);
  }

  private matchesArtworkSearch(artwork: Artwork, query: string): boolean {
    const searchableFields = [
      artwork.title.it,
      artwork.title.en,
      artwork.subtitle.it,
      artwork.subtitle.en,
      artwork.technique.it,
      artwork.technique.en,
      artwork.support.it,
      artwork.support.en,
      artwork.texts.description.it,
      artwork.texts.description.en,
      artwork.texts.poetic.it,
      artwork.texts.poetic.en,
      String(artwork.year),
      ...artwork.tags.flatMap((tag) => [tag.name.it, tag.name.en])
    ];

    const haystack = this.normalizeSearchValue(searchableFields.join(' '));
    return haystack.includes(query);
  }

  private normalizeSearchValue(value: string): string {
    return String(value || '')
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .toLowerCase()
      .trim();
  }
}
