import { Component } from '@angular/core';
import { Input } from '@angular/core';
import { SiteLanguage } from '../../interfaces/language.interface';
import { CookieConsentService } from '../../services/cookie-consent.service';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

@Component({
  selector: 'app-cookie-banner',
  standalone: true,
  templateUrl: './cookie-banner.component.html',
  styleUrl: './cookie-banner.component.sass'
})
export class CookieBannerComponent {
  @Input() language: SiteLanguage = 'it';
  protected visible = false;

  constructor(private readonly cookieConsentService: CookieConsentService) {
    this.cookieConsentService
      .getConsent$()
      .pipe(takeUntilDestroyed())
      .subscribe((consent) => {
        this.visible = !consent;
      });
  }

  protected acceptAnalytics(): void {
    this.cookieConsentService.saveConsent({ analytics: true });
    this.visible = false;
  }

  protected rejectAnalytics(): void {
    this.cookieConsentService.saveConsent({ analytics: false });
    this.visible = false;
  }
}
