import { DOCUMENT } from '@angular/common';
import { Inject, Injectable } from '@angular/core';
import { SiteAnalyticsConfig } from '../interfaces/site-config.interface';

declare global {
  interface Window {
    dataLayer?: unknown[];
    gtag?: (...args: unknown[]) => void;
  }
}

@Injectable({
  providedIn: 'root'
})
export class AnalyticsService {
  private initializedMeasurementId: string | null = null;

  constructor(@Inject(DOCUMENT) private readonly document: Document) {}

  initialize(config: SiteAnalyticsConfig): void {
    if (!config.enabled || !config.googleAnalyticsId) {
      return;
    }

    if (this.initializedMeasurementId === config.googleAnalyticsId) {
      return;
    }

    this.ensureGoogleScript(config.googleAnalyticsId);

    window.dataLayer = window.dataLayer || [];
    window.gtag =
      window.gtag ||
      function gtag(...args: unknown[]) {
        window.dataLayer?.push(args);
      };

    window.gtag('js', new Date());
    window.gtag('config', config.googleAnalyticsId, {
      send_page_view: false
    });

    this.initializedMeasurementId = config.googleAnalyticsId;
  }

  trackPageView(url: string, title: string): void {
    if (!this.initializedMeasurementId || !window.gtag) {
      return;
    }

    window.gtag('event', 'page_view', {
      page_title: title,
      page_location: url,
      page_path: new URL(url).pathname
    });
  }

  private ensureGoogleScript(measurementId: string): void {
    const existingScript = this.document.head.querySelector(
      `script[data-analytics-id="${measurementId}"]`
    ) as HTMLScriptElement | null;

    if (existingScript) {
      return;
    }

    const script = this.document.createElement('script');
    script.async = true;
    script.src = `https://www.googletagmanager.com/gtag/js?id=${measurementId}`;
    script.setAttribute('data-analytics-id', measurementId);
    this.document.head.appendChild(script);
  }
}
